-- ============================================================================
-- 1. Загрузка планов ТО оборудования для СИ
-- ============================================================================
-- id генерируется автоматически.
-- equipment_id определяется по accounting_number из equipment.
-- Дубликаты проверяются по (equipment_id + name) через NOT EXISTS.
-- Примечание: accounting_number='35' имеет 2 записи в equipment,
--   LIMIT 1 выберет первую (Термоанализатор STA 449 F5 Jupiter).

SELECT setval('equipment_maintenance_plans_id_seq',
              (SELECT COALESCE(MAX(id), 0) FROM equipment_maintenance_plans) + 1);

INSERT INTO equipment_maintenance_plans (
    equipment_id, name,
    frequency_count, frequency_unit, frequency_period_value,
    frequency_condition, is_condition_based, is_active, notes
)
SELECT
    v.equipment_id, v.name,
    v.frequency_count, v.frequency_unit, v.frequency_period_value,
    v.frequency_condition, v.is_condition_based, v.is_active, v.notes
FROM (VALUES
    ((SELECT id FROM equipment WHERE accounting_number = '58.1' LIMIT 1), 'ТО-1', 1, 'WEEK', 1, '', FALSE, TRUE, 'Провести чистку сенсорного экрана'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.1' LIMIT 1), 'ТО-2', 1, 'YEAR', 5, 'При необходимости, но не реже', TRUE, TRUE, 'Заменить предохранители входного модуля мощности'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.1' LIMIT 1), 'ТО-3', 1, 'WEEK', 1, '', FALSE, TRUE, 'Слить воду из компрессора'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.1' LIMIT 1), 'ТО-4', 1, 'MONTH', 3, '', FALSE, TRUE, 'Сушка фильтра'),
    ((SELECT id FROM equipment WHERE accounting_number = '55' LIMIT 1), 'ТО-1', 1, 'MONTH', 1, '', FALSE, TRUE, 'Провести чистку ячейки'),
    ((SELECT id FROM equipment WHERE accounting_number = '55' LIMIT 1), 'ТО-2', 1, 'YEAR', 5, 'При необходимости, но не реже', TRUE, TRUE, 'Провести замену предохранителей'),
    ((SELECT id FROM equipment WHERE accounting_number = 'ВТ-33' LIMIT 1), 'ТО-1', 1, 'WEEK', 1, '', FALSE, TRUE, 'Провести чистку корпуса весов'),
    ((SELECT id FROM equipment WHERE accounting_number = 'ВТ-33' LIMIT 1), 'ТО-2', 1, 'WEEK', 1, '', FALSE, TRUE, 'Провести чистку циферблата весов'),
    ((SELECT id FROM equipment WHERE accounting_number = 'ВТ-33' LIMIT 1), 'ТО-3', 1, 'WEEK', 1, '', FALSE, TRUE, 'Проверить установку весов по уровню'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-5' LIMIT 1), 'ТО-1', NULL, NULL, NULL, 'При смене цвета осушителя с синего на розовый', TRUE, TRUE, 'Провести сушку осушителя для воздушного компрессора'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-5' LIMIT 1), 'ТО-2', 1, 'MONTH', 3, '', FALSE, TRUE, 'Провести профилактический осмотр печи'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-6' LIMIT 1), 'ТО-1', NULL, NULL, NULL, 'При перемещении прибора', TRUE, TRUE, 'Провести проверку ровного положения прибора уровнем'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-6' LIMIT 1), 'ТО-2', NULL, NULL, NULL, 'По мере загрязнения', TRUE, TRUE, 'Заменить водяной фильтр'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-6' LIMIT 1), 'ТО-3', 1, 'MONTH', 1, '', FALSE, TRUE, 'Провести визуальную проверку фильтра на загрязнения'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-6' LIMIT 1), 'ТО-4', 1, 'YEAR', 3, '', FALSE, TRUE, 'Провести чистку кварцевой защитной трубки, держателя и зонда'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-6' LIMIT 1), 'ТО-5', 1, 'MONTH', 3, '', FALSE, TRUE, 'Провести профилактический осмотр печи'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-28' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Смазывание и регулировка микрометрической пары'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Ц-45' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Смазывание и регулировка микрометрической пары'),
    ((SELECT id FROM equipment WHERE accounting_number = 'М-13' LIMIT 1), 'ТО-1', 1, 'MONTH', 1, '', FALSE, TRUE, 'Провести чистку ячейки'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-7' LIMIT 1), 'ТО-1', 1, 'MONTH', 1, '', FALSE, TRUE, 'Провести визуальный осмотр и протереть оборудование'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-7' LIMIT 1), 'ТО-2', 1, 'MONTH', 6, '', FALSE, TRUE, 'Заменить воду в охлаждающей системе'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-4' LIMIT 1), 'ТО-1', 1, 'MONTH', 1, '', FALSE, TRUE, 'Провести чистку ячейки'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Ц-108' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Провести смазывание и регулировку микрометрической пары'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-8' LIMIT 1), 'ТО-1', 1, 'MONTH', 6, '', FALSE, TRUE, 'Сушка картриджей'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-8' LIMIT 1), 'ТО-2', 1, 'YEAR', 5, 'В случае поломки', TRUE, TRUE, 'Замена лазерного модуля'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-8' LIMIT 1), 'ТО-3', 1, 'YEAR', 5, 'В случае поломки', TRUE, TRUE, 'Замена ИК источника'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Д-8' LIMIT 1), 'ТО-4', 1, 'YEAR', 5, 'В случае поломки', TRUE, TRUE, 'Замена предохранителей'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Ц-122' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Протереть штангенциркуль салфеткой, смоченной в водно-щелочном растворе СОЖ, а затем насухо чистой салфеткой'),
    ((SELECT id FROM equipment WHERE accounting_number = '35' LIMIT 1), 'ТО-1', NULL, NULL, NULL, 'При смене цвета осушителя с синего на розовый', TRUE, TRUE, 'Провести сушку осушителя для воздушного компрессора'),
    ((SELECT id FROM equipment WHERE accounting_number = '35' LIMIT 1), 'ТО-2', 1, 'YEAR', 3, '', FALSE, TRUE, 'Провести профилактический осмотр печи'),
    ((SELECT id FROM equipment WHERE accounting_number = '65' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Смазать подвижные части (шарниры, замок)'),
    ((SELECT id FROM equipment WHERE accounting_number = '65' LIMIT 1), 'ТО-2', 1, 'YEAR', 1, '', FALSE, TRUE, 'Проверить плотность затяжки винтов шарниров'),
    ((SELECT id FROM equipment WHERE accounting_number = '65' LIMIT 1), 'ТО-3', 1, 'YEAR', 1, '', FALSE, TRUE, 'Провести калибровку оборудования'),
    ((SELECT id FROM equipment WHERE accounting_number = '65' LIMIT 1), 'ТО-4', 1, 'MONTH', 6, '', FALSE, TRUE, 'Провести очистку рабочей камеры, металлических и стеклянных поверхнойстей, пластиковых деталей'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.2' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Провести визуальный осмотр резервуара, всех внешних компонентов и линий'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.2' LIMIT 1), 'ТО-2', 1, 'YEAR', 1, '', FALSE, TRUE, 'Проверить герметичность на максимально допустимом рабочем давлении или на пределе главного предохранительного клапана'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.2' LIMIT 1), 'ТО-3', 1, 'YEAR', 1, '', FALSE, TRUE, 'Провести функциональное тестирование клапанов, предохранительных устройств'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.3' LIMIT 1), 'ТО-1', 1, 'MONTH', 6, '', FALSE, TRUE, 'Провести визуальный осмотр резервуара, всех внешних компонентов и линий'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.3' LIMIT 1), 'ТО-2', 1, 'YEAR', 1, '', FALSE, TRUE, 'Проверить герметичность на максимально допустимом рабочем давлении или на пределе главного предохранительного клапана'),
    ((SELECT id FROM equipment WHERE accounting_number = '58.3' LIMIT 1), 'ТО-3', 1, 'YEAR', 1, '', FALSE, TRUE, 'Провести функциональное тестирование клапанов, предохранительных устройств'),
    ((SELECT id FROM equipment WHERE accounting_number = 'ЦП-69' LIMIT 1), 'ТО-1', 1, 'MONTH', 3, '', FALSE, TRUE, 'Уборка и разморозка холодильника'),
    ((SELECT id FROM equipment WHERE accounting_number = 'ЦП-69' LIMIT 1), 'ТО-2', 4, 'YEAR', 1, '', FALSE, TRUE, 'Разморозка морозильной камеры'),
    ((SELECT id FROM equipment WHERE accounting_number = 'М-4' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Слить остатки жидкого азота и полностью отогреть до сухого состояния'),
    ((SELECT id FROM equipment WHERE accounting_number = 'М-14' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Слить остатки жидкого азота и полностью отогреть до сухого состояния'),
    ((SELECT id FROM equipment WHERE accounting_number = 'М-15' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Слить остатки жидкого азота и полностью отогреть до сухого состояния'),
    ((SELECT id FROM equipment WHERE accounting_number = 'Ц-144' LIMIT 1), 'ТО-1', 1, 'YEAR', 1, '', FALSE, TRUE, 'Слить остатки жидкого азота и полностью отогреть до сухого состояния')
) AS v(
    equipment_id, name,
    frequency_count, frequency_unit, frequency_period_value,
    frequency_condition, is_condition_based, is_active, notes
)
WHERE NOT EXISTS (
    SELECT 1 FROM equipment_maintenance_plans p
    WHERE p.equipment_id = v.equipment_id
      AND p.name = v.name
);

UPDATE equipment_maintenance_plans
SET equipment_id = (
    SELECT id FROM equipment
    WHERE accounting_number = '35'
      AND name = 'Термоанализатор синхронный STA 449 F5 Jupiter'
    LIMIT 1
)
WHERE equipment_id = (
    SELECT id FROM equipment
    WHERE accounting_number = '35'
      AND name != 'Термоанализатор синхронный STA 449 F5 Jupiter'
    LIMIT 1
);


DO $$
BEGIN
    IF (SELECT MAX(id) FROM equipment_maintenance_logs) IS NOT NULL THEN
        PERFORM setval('equipment_maintenance_logs_id_seq', (SELECT MAX(id) FROM equipment_maintenance_logs));
    END IF;
END $$;

INSERT INTO equipment_maintenance_logs (
    plan_id, performed_date, performed_by_id, verified_by_id,
    status, verified_date, notes
)
SELECT
    v.plan_id, v.performed_date::date, v.performed_by_id, v.verified_by_id,
    v.status, v.verified_date::date, v.notes
FROM (VALUES
    ((SELECT p.id FROM equipment_maintenance_plans p JOIN equipment e ON e.id = p.equipment_id WHERE e.accounting_number = '65' AND p.name = 'ТО-4' LIMIT 1), '2022-12-25', (SELECT id FROM users WHERE last_name = 'Кадимова' LIMIT 1), (SELECT id FROM users WHERE last_name = 'Кадимова' LIMIT 1), 'COMPLETED', '2022-12-25', ''),
    ((SELECT p.id FROM equipment_maintenance_plans p JOIN equipment e ON e.id = p.equipment_id WHERE e.accounting_number = '65' AND p.name = 'ТО-1' LIMIT 1), '2022-12-25', (SELECT id FROM users WHERE last_name = 'Кадимова' LIMIT 1), (SELECT id FROM users WHERE last_name = 'Кадимова' LIMIT 1), 'COMPLETED', '2022-12-25', ''),
    ((SELECT p.id FROM equipment_maintenance_plans p JOIN equipment e ON e.id = p.equipment_id WHERE e.accounting_number = '65' AND p.name = 'ТО-2' LIMIT 1), '2022-12-25', (SELECT id FROM users WHERE last_name = 'Кадимова' LIMIT 1), (SELECT id FROM users WHERE last_name = 'Кадимова' LIMIT 1), 'COMPLETED', '2022-12-25', ''),
    ((SELECT p.id FROM equipment_maintenance_plans p JOIN equipment e ON e.id = p.equipment_id WHERE e.accounting_number = '65' AND p.name = 'ТО-3' LIMIT 1), '2023-05-26', (SELECT id FROM users WHERE last_name = 'Кречетова' LIMIT 1), (SELECT id FROM users WHERE last_name = 'Кречетова' LIMIT 1), 'COMPLETED', '2023-05-26', ''),
    ((SELECT p.id FROM equipment_maintenance_plans p JOIN equipment e ON e.id = p.equipment_id WHERE e.accounting_number = '65' AND p.name = 'ТО-4' LIMIT 1), '2023-06-29', (SELECT id FROM users WHERE last_name = 'Медведева' LIMIT 1), (SELECT id FROM users WHERE last_name = 'Медведева' LIMIT 1), 'COMPLETED', '2023-06-29', ''),
    ((SELECT p.id FROM equipment_maintenance_plans p JOIN equipment e ON e.id = p.equipment_id WHERE e.accounting_number = '65' AND p.name = 'ТО-1' LIMIT 1), '2023-12-28', (SELECT id FROM users WHERE last_name = 'Кречетова' LIMIT 1), (SELECT id FROM users WHERE last_name = 'Кречетова' LIMIT 1), 'COMPLETED', '2023-12-28', ''),
