) AS v(
    plan_id, performed_date, performed_by_id, verified_by_id,
    status, verified_date, notes
)
WHERE NOT EXISTS (
    SELECT 1 FROM equipment_maintenance_logs l
    WHERE l.plan_id = v.plan_id
      AND l.performed_date = v.performed_date::date
      AND l.performed_by_id = v.performed_by_id
);

UPDATE equipment_maintenance_plans p
SET next_due_date = l.performed_date + (
    CASE p.frequency_unit
        WHEN 'DAY'   THEN make_interval(days  => p.frequency_period_value::int)
        WHEN 'WEEK'  THEN make_interval(weeks => p.frequency_period_value::int)
        WHEN 'MONTH' THEN make_interval(months => p.frequency_period_value::int)
        WHEN 'YEAR'  THEN make_interval(years  => p.frequency_period_value::int)
    END / NULLIF(p.frequency_count, 0)
),
updated_at = CURRENT_TIMESTAMP
FROM equipment_maintenance_logs l
WHERE l.plan_id = p.id
  AND l.status IN ('COMPLETED', 'OVERDUE')
  AND l.performed_date = (
      SELECT MAX(l2.performed_date)
      FROM equipment_maintenance_logs l2
      WHERE l2.plan_id = p.id
        AND l2.status IN ('COMPLETED', 'OVERDUE')
  );
  
COMMIT;
